   224→// Update checklist item completion
   225→router.post('/checklists/:id/complete', authMiddleware, async (req, res) => {
   226→  try {
   227→    const { item_id } = req.body;
   228→
   229→    const checklist = await pool.query(
   230→      'SELECT * FROM onboarding_checklists WHERE id = $1 AND candidate_id = $2',
   231→      [req.params.id, req.user.id]
   232→    );
   233→
   234→    if (checklist.rows.length === 0) {
   235→      return res.status(404).json({ error: 'Checklist not found' });
   236→    }
   237→
   238→    const completedItems = checklist.rows[0].completed_items || [];
   239→    if (!completedItems.includes(item_id)) {
   240→      completedItems.push(item_id);
   241→    }
   242→
   243→    const items = checklist.rows[0].items || [];
   244→    const allCompleted = items.every(item => completedItems.includes(item.id));
   245→
   246→    const result = await pool.query(
   247→      `UPDATE onboarding_checklists
   248→       SET completed_items = $1,
   249→           status = $2,
   250→           completed_at = $3,
   251→           updated_at = NOW()
   252→       WHERE id = $4
   253→       RETURNING *`,
   254→      [
   255→        JSON.stringify(completedItems),
   256→        allCompleted ? 'completed' : 'in_progress',
   257→        allCompleted ? new Date() : null,
   258→        req.params.id
   259→      ]
   260→    );
   261→
   262→    res.json(result.rows[0]);
