      { id: 7, task: 'Complete IT setup (email, laptop)', required: false },
      { id: 8, task: 'Schedule first day orientation', required: true }
    ];

    await pool.query(
      `INSERT INTO onboarding_checklists
       (offer_id, candidate_id, title, description, items, due_date)
       VALUES ($1, $2, $3, $4, $5, $6)`,
      [
        offer.id,
        offer.candidate_id,
