    );
    if (parseInt(existingDocs.rows[0].cnt) === 0) {
      // No real documents = the old system faked it. Reset.
      await pool.query(
        `UPDATE onboarding_checklists SET
          status = 'in_progress',
          completed_items = '[]'::jsonb,
          completed_at = NULL,
          updated_at = NOW()
         WHERE id = $1`,
        [cl.id]
      );
      cl.status = 'in_progress';
      cl.completed_items = [];
    }
  }
}

